// Curated Trend "Perspectives" (the detail-page accordion content).
// Source of truth + how this is produced: docs/PERSPECTIVES_PLAN.md.
//
// Generated by scripts/workflows/perspectives.workflow.js (survey -> shape gate ->
// per-camp research -> verify -> synthesize -> final-copy verify), then curated.
// This file currently holds the VERIFIED prototype output for the AI Safety
// Evaluation Crisis; the full run over all 22 trends populates the remaining
// entries. scripts/seed-trend-perspectives.ts writes these to the `perspectives`
// column by slug and touches nothing else. A value of null means the shape gate
// said "skip" (no real debate), so no section renders for that trend.

export type PerspectiveSource = { title: string; url: string };

export type PerspectiveStance = {
  label: string; // trend-specific stance label
  who: string; // attribution: camp / archetype / verified orgs
  summary: string; // ONE sentence, shown in the collapsed box
  body: string; // the fuller reasoning, shown when expanded
  sources: PerspectiveSource[]; // 0-2 real "further reading" links
};

export type Perspectives = {
  shape: "binary" | "multiple" | "tradeoff";
  intro: string; // one-sentence framing of the fight (may be empty)
  stances: PerspectiveStance[];
  leans: string; // honest synthesis, or "genuinely contested"
};

